+    private static func makeRequest(
+        path: String,
+        body: [String: Any],
+        httpsPort: Int,
+        httpPort: Int?,
+        csrfToken: String,
+        timeout: TimeInterval) async throws -> Data
+    {
+        do {
+            return try await Self.sendRequest(
+                scheme: "https",
+                port: httpsPort,
+                path: path,
+                body: body,
+                csrfToken: csrfToken,
+                timeout: timeout)
+        } catch {
+            guard let httpPort, httpPort != httpsPort else { throw error }
+            return try await Self.sendRequest(
+                scheme: "http",
+                port: httpPort,
+                path: path,
+                body: body,
+                csrfToken: csrfToken,
+                timeout: timeout)
+        }
+    }
+
+    private static func sendRequest(
+        scheme: String,
+        port: Int,
+        path: String,
+        body: [String: Any],
+        csrfToken: String,
+        timeout: TimeInterval) async throws -> Data
+    {
+        guard let url = URL(string: "\(scheme)://127.0.0.1:\(port)\(path)") else {
+            throw AntigravityStatusProbeError.apiError("Invalid URL")
+        }
+
+        let payload = try JSONSerialization.data(withJSONObject: body, options: [])
+        var request = URLRequest(url: url)
+        request.httpMethod = "POST"
+        request.httpBody = payload
+        request.timeoutInterval = timeout
+        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
+        request.setValue(String(payload.count), forHTTPHeaderField: "Content-Length")
+        request.setValue("1", forHTTPHeaderField: "Connect-Protocol-Version")
+        request.setValue(csrfToken, forHTTPHeaderField: "X-Codeium-Csrf-Token")
+
+        let config = URLSessionConfiguration.ephemeral
+        config.timeoutIntervalForRequest = timeout
+        config.timeoutIntervalForResource = timeout
+        let session = URLSession(configuration: config, delegate: InsecureSessionDelegate(), delegateQueue: nil)
+        defer { session.invalidateAndCancel() }
+
+        let (data, response) = try await session.data(for: request)
+        guard let http = response as? HTTPURLResponse else {
+            throw AntigravityStatusProbeError.apiError("Invalid response")
+        }
+        guard http.statusCode == 200 else {
+            let message = String(data: data, encoding: .utf8) ?? ""
+            throw AntigravityStatusProbeError.apiError("HTTP \(http.statusCode): \(message)")
+        }
+        return data
+    }
+}
+
+private final class InsecureSessionDelegate: NSObject, URLSessionDelegate {
+    func urlSession(
+        _ session: URLSession,
+        didReceive challenge: URLAuthenticationChallenge,
+        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void)
+    {
+        if let trust = challenge.protectionSpace.serverTrust {
+            completionHandler(.useCredential, URLCredential(trust: trust))
+        } else {
+            completionHandler(.performDefaultHandling, nil)
+        }
+    }
+}
